// ============================================================
// PKCE Utilities
// ============================================================
function generateRandomString(length) {
  const charset = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-._~';
  const randomValues = new Uint8Array(length);
  window.crypto.getRandomValues(randomValues);
  return Array.from(randomValues)
    .map((v) => charset[v % charset.length])
    .join('');
}

async function generateCodeChallenge(codeVerifier) {
  const encoder = new TextEncoder();
  const data = encoder.encode(codeVerifier);
  const digest = await window.crypto.subtle.digest('SHA-256', data);
  return base64UrlEncode(digest);
}

function base64UrlEncode(arrayBuffer) {
  const bytes = new Uint8Array(arrayBuffer);
  let binary = '';
  bytes.forEach((b) => (binary += String.fromCharCode(b)));
  return btoa(binary).replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
}

// ============================================================
// Token Storage Utilities
// ============================================================
const TOKEN_KEYS = {
  accessToken: 'oauth_access_token',
  refreshToken: 'oauth_refresh_token',
  tokenType: 'oauth_token_type',
  expiresAt: 'oauth_expires_at',
  idToken: 'oauth_id_token',
};

function storeTokens(tokenResponse) {
  const expiresAt = Date.now() + tokenResponse.expires_in * 1000;
  localStorage.setItem(TOKEN_KEYS.accessToken, tokenResponse.access_token);
  localStorage.setItem(TOKEN_KEYS.tokenType, tokenResponse.token_type || 'Bearer');
  localStorage.setItem(TOKEN_KEYS.expiresAt, expiresAt.toString());

  if (tokenResponse.refresh_token) {
    localStorage.setItem(TOKEN_KEYS.refreshToken, tokenResponse.refresh_token);
  }
  if (tokenResponse.id_token) {
    localStorage.setItem(TOKEN_KEYS.idToken, tokenResponse.id_token);
  }
}

function getStoredTokens() {
  return {
    accessToken: localStorage.getItem(TOKEN_KEYS.accessToken),
    refreshToken: localStorage.getItem(TOKEN_KEYS.refreshToken),
    tokenType: localStorage.getItem(TOKEN_KEYS.tokenType),
    expiresAt: parseInt(localStorage.getItem(TOKEN_KEYS.expiresAt) || '0', 10),
    idToken: localStorage.getItem(TOKEN_KEYS.idToken),
  };
}

function clearStoredTokens() {
  Object.values(TOKEN_KEYS).forEach((key) => localStorage.removeItem(key));
  sessionStorage.removeItem('oauth_code_verifier');
  sessionStorage.removeItem('oauth_state');
}

function isTokenExpired() {
  const expiresAt = parseInt(localStorage.getItem(TOKEN_KEYS.expiresAt) || '0', 10);
  // Consider token expired 60 seconds before actual expiry
  return Date.now() >= expiresAt - 60000;
}

// ============================================================
// OAuth API Functions
// ============================================================
async function initiateAuthorizationRequest() {
  // Generate PKCE code verifier and challenge
  const codeVerifier = generateRandomString(128);
  const codeChallenge = await generateCodeChallenge(codeVerifier);

  // Generate state parameter for CSRF protection
  const state = generateRandomString(64);

  // Store code verifier and state in sessionStorage (survives redirect)
  sessionStorage.setItem('oauth_code_verifier', codeVerifier);
  sessionStorage.setItem('oauth_state', state);

  // Build authorization URL
  const params = new URLSearchParams({
    response_type: 'code',
    client_id: OAUTH_CONFIG.clientId,
    redirect_uri: OAUTH_CONFIG.redirectUri,
    scope: OAUTH_CONFIG.scope,
    state: state,
    code_challenge: codeChallenge,
    code_challenge_method: 'S256',
  });

  const authUrl = `${OAUTH_CONFIG.authorizationEndpoint}?${params.toString()}`;

  // Redirect to authorization server
  window.location.href = authUrl;
}

async function exchangeCodeForTokens(authorizationCode, state) {
  // Verify state parameter
  const storedState = sessionStorage.getItem('oauth_state');
  if (!storedState || storedState !== state) {
    throw new Error('Invalid state parameter. Possible CSRF attack.');
  }

  // Retrieve PKCE code verifier
  const codeVerifier = sessionStorage.getItem('oauth_code_verifier');
  if (!codeVerifier) {
    throw new Error('Missing PKCE code verifier. Authentication flow is invalid.');
  }

  const body = new URLSearchParams({
    grant_type: 'authorization_code',
    code: authorizationCode,
    redirect_uri: OAUTH_CONFIG.redirectUri,
    client_id: OAUTH_CONFIG.clientId,
    code_verifier: codeVerifier,
  });

  const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
    },
    body: body.toString(),
  });

  if (!response.ok) {
    const errorData = await response.json().catch(() => ({}));
    throw new Error(
      `Token exchange failed: ${errorData.error_description || errorData.error || response.statusText}`
    );
  }

  const tokenResponse = await response.json();

  // Clean up PKCE and state from sessionStorage
  sessionStorage.removeItem('oauth_code_verifier');
  sessionStorage.removeItem('oauth_state');

  // Store tokens
  storeTokens(tokenResponse);

  return tokenResponse;
}

async function refreshAccessToken() {
  const { refreshToken } = getStoredTokens();

  if (!refreshToken) {
    throw new Error('No refresh token available.');
  }

  const body = new URLSearchParams({
    grant_type: 'refresh_token',
    refresh_token: refreshToken,
    client_id: OAUTH_CONFIG.clientId,
  });

  const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
    },
    body: body.toString(),
  });

  if (!response.ok) {
    const errorData = await response.json().catch(() => ({}));
    // If refresh fails, clear tokens and force re-authentication
    clearStoredTokens();
    throw new Error(
      `Token refresh failed: ${errorData.error_description || errorData.error || response.statusText}`
    );
  }

  const tokenResponse = await response.json();
  storeTokens(tokenResponse);

  return tokenResponse;
}

// ============================================================
// Authenticated Fetch Wrapper
// ============================================================
async function authenticatedFetch(url, options = {}) {
  let { accessToken, tokenType } = getStoredTokens();

  // Check if token is expired and try to refresh
  if (isTokenExpired()) {
    try {
      const newTokens = await refreshAccessToken();
      accessToken = newTokens.access_token;
      tokenType = newTokens.token_type || 'Bearer';
    } catch (error) {
      // Refresh failed, need to re-authenticate
      throw new Error('Authentication expired. Please log in again.');
    }
  }

  if (!accessToken) {
    throw new Error('No access token available. Please log in.');
  }

  const headers = {
    ...options.headers,
    Authorization: `${tokenType} ${accessToken}`,
  };

  const response = await fetch(url, { ...options, headers });

  // Handle 401 - try token refresh once
  if (response.status === 401) {
    try {
      const newTokens = await refreshAccessToken();
      headers.Authorization = `${newTokens.token_type || 'Bearer'} ${newTokens.access_token}`;
      return fetch(url, { ...options, headers });
    } catch (refreshError) {
      clearStoredTokens();
      throw new Error('Authentication expired. Please log in again.');
    }
  }

  return response;
}

